import { describe, expect, it } from 'vitest'
import {
  applyMove,
  canMove,
  createInitialGame,
  createEmptyBoard,
  hasWinningTile,
} from './logic'
import type { Board } from './types'

const withRandomSequence = <T>(values: number[], callback: () => T): T => {
  const original = Math.random
  let index = 0
  Math.random = () => {
    const value = values[index]
    index += 1
    return value ?? 0
  }

  try {
    return callback()
  } finally {
    Math.random = original
  }
}

describe('2048 game logic', () => {
  it('creates an empty 4x4 board', () => {
    expect(createEmptyBoard()).toEqual([
      [null, null, null, null],
      [null, null, null, null],
      [null, null, null, null],
      [null, null, null, null],
    ])
  })

  it('creates an initial game with two spawned tiles and zero score', () => {
    const game = withRandomSequence([0, 0, 0.99, 0], () => createInitialGame())

    expect(game.score).toBe(0)
    expect(game.won).toBe(false)
    expect(game.gameOver).toBe(false)
    expect(game.board.flat().filter(Boolean)).toHaveLength(2)
    expect(game.board[0][0]).toBe(2)
    expect(game.board[3][3]).toBe(2)
  })

  it('slides tiles left and merges matching neighbors once', () => {
    const board: Board = [
      [2, null, 2, 4],
      [null, null, null, null],
      [null, null, null, null],
      [null, null, null, null],
    ]

    const result = withRandomSequence([0, 0], () => applyMove(board, 'left'))

    expect(result.board[0]).toEqual([4, 4, null, null])
    expect(result.scoreGained).toBe(4)
    expect(result.moved).toBe(true)
  })

  it('does not allow a tile to merge twice in one move', () => {
    const board: Board = [
      [2, 2, 2, 2],
      [null, null, null, null],
      [null, null, null, null],
      [null, null, null, null],
    ]

    const result = withRandomSequence([0.99, 0], () => applyMove(board, 'left'))

    expect(result.board[0]).toEqual([4, 4, null, 2])
    expect(result.scoreGained).toBe(8)
  })

  it('does not spawn a tile when a move changes nothing', () => {
    const board: Board = [
      [2, 4, 8, 16],
      [32, 64, 128, 256],
      [512, 1024, 2, 4],
      [8, 16, 32, 64],
    ]

    const result = applyMove(board, 'left')

    expect(result.board).toEqual(board)
    expect(result.moved).toBe(false)
    expect(result.scoreGained).toBe(0)
  })

  it('detects a winning tile after a move', () => {
    const board: Board = [
      [1024, 1024, null, null],
      [null, null, null, null],
      [null, null, null, null],
      [null, null, null, null],
    ]

    const result = withRandomSequence([0.99, 0], () => applyMove(board, 'left'))

    expect(result.won).toBe(true)
    expect(hasWinningTile(result.board)).toBe(true)
  })

  it('detects when no moves remain', () => {
    const board: Board = [
      [2, 4, 2, 4],
      [4, 2, 4, 2],
      [2, 4, 2, 4],
      [4, 2, 4, 2],
    ]

    expect(canMove(board)).toBe(false)
    const result = applyMove(board, 'up')
    expect(result.gameOver).toBe(true)
  })
})

import type { Board, Direction, GameSnapshot, MoveResult } from './types'

const BOARD_SIZE = 4
const WINNING_VALUE = 2048

export const createEmptyBoard = (): Board =>
  Array.from({ length: BOARD_SIZE }, () => Array.from({ length: BOARD_SIZE }, () => null))

const cloneBoard = (board: Board): Board => board.map((row) => [...row])

const boardsEqual = (a: Board, b: Board): boolean =>
  a.every((row, rowIndex) => row.every((cell, colIndex) => cell === b[rowIndex][colIndex]))

const getEmptyPositions = (board: Board): Array<{ row: number; col: number }> => {
  const positions: Array<{ row: number; col: number }> = []

  board.forEach((row, rowIndex) => {
    row.forEach((cell, colIndex) => {
      if (cell === null) {
        positions.push({ row: rowIndex, col: colIndex })
      }
    })
  })

  return positions
}

const spawnRandomTile = (board: Board): Board => {
  const emptyPositions = getEmptyPositions(board)
  if (emptyPositions.length === 0) {
    return board
  }

  const nextBoard = cloneBoard(board)
  const target = emptyPositions[Math.floor(Math.random() * emptyPositions.length)]
  nextBoard[target.row][target.col] = Math.random() < 0.9 ? 2 : 4
  return nextBoard
}

const slideAndMergeLine = (line: Board[number]): { line: Board[number]; scoreGained: number } => {
  const filtered = line.filter((value): value is number => value !== null)
  const merged: Array<number | null> = []
  let scoreGained = 0

  for (let index = 0; index < filtered.length; index += 1) {
    const current = filtered[index]
    const next = filtered[index + 1]

    if (current === next) {
      const mergedValue = current * 2
      merged.push(mergedValue)
      scoreGained += mergedValue
      index += 1
    } else {
      merged.push(current)
    }
  }

  while (merged.length < BOARD_SIZE) {
    merged.push(null)
  }

  return { line: merged, scoreGained }
}

const transpose = (board: Board): Board =>
  board[0].map((_, colIndex) => board.map((row) => row[colIndex]))

const reverseRows = (board: Board): Board => board.map((row) => [...row].reverse())

const normalizeForMove = (board: Board, direction: Direction): Board => {
  switch (direction) {
    case 'left':
      return cloneBoard(board)
    case 'right':
      return reverseRows(board)
    case 'up':
      return transpose(board)
    case 'down':
      return reverseRows(transpose(board))
  }
}

const denormalizeFromMove = (board: Board, direction: Direction): Board => {
  switch (direction) {
    case 'left':
      return cloneBoard(board)
    case 'right':
      return reverseRows(board)
    case 'up':
      return transpose(board)
    case 'down':
      return transpose(reverseRows(board))
  }
}

export const hasWinningTile = (board: Board): boolean =>
  board.some((row) => row.some((cell) => cell === WINNING_VALUE))

export const canMove = (board: Board): boolean => {
  if (getEmptyPositions(board).length > 0) {
    return true
  }

  for (let row = 0; row < BOARD_SIZE; row += 1) {
    for (let col = 0; col < BOARD_SIZE; col += 1) {
      const value = board[row][col]
      if (row + 1 < BOARD_SIZE && board[row + 1][col] === value) {
        return true
      }
      if (col + 1 < BOARD_SIZE && board[row][col + 1] === value) {
        return true
      }
    }
  }

  return false
}

export const applyMove = (board: Board, direction: Direction): MoveResult => {
  const normalized = normalizeForMove(board, direction)
  let scoreGained = 0
  const movedBoard = normalized.map((row) => {
    const result = slideAndMergeLine(row)
    scoreGained += result.scoreGained
    return result.line
  })
  const denormalized = denormalizeFromMove(movedBoard, direction)
  const moved = !boardsEqual(board, denormalized)
  const nextBoard = moved ? spawnRandomTile(denormalized) : denormalized

  return {
    board: nextBoard,
    scoreGained,
    moved,
    won: hasWinningTile(nextBoard),
    gameOver: !canMove(nextBoard),
  }
}

export const createInitialGame = (): GameSnapshot => {
  const firstSpawn = spawnRandomTile(createEmptyBoard())
  const secondSpawn = spawnRandomTile(firstSpawn)

  return {
    board: secondSpawn,
    score: 0,
    won: false,
    gameOver: false,
  }
}

