import type { Board } from '../game/types'

interface GameBoardProps {
  board: Board
}

const tileClassName = (value: number | null): string => {
  if (value === null) {
    return 'tile tile--empty'
  }

  return `tile tile--${value}`
}

export function GameBoard({ board }: GameBoardProps) {
  return (
    <div className="board" aria-label="2048 game board" role="grid">
      {board.flatMap((row, rowIndex) =>
        row.map((value, colIndex) => (
          <div
            className={tileClassName(value)}
            key={`${rowIndex}-${colIndex}`}
            role="gridcell"
            aria-label={value === null ? 'empty tile' : `tile ${value}`}
          >
            {value ?? ''}
          </div>
        )),
      )}
    </div>
  )
}

import { useEffect, useMemo, useState } from 'react'
import { GameBoard } from './components/GameBoard'
import { ScorePanel } from './components/ScorePanel'
import { applyMove, createInitialGame } from './game/logic'
import type { Direction, GameSnapshot } from './game/types'
import './App.css'

const KEY_TO_DIRECTION: Record<string, Direction> = {
  ArrowUp: 'up',
  ArrowDown: 'down',
  ArrowLeft: 'left',
  ArrowRight: 'right',
  w: 'up',
  a: 'left',
  s: 'down',
  d: 'right',
}

function App() {
  const [game, setGame] = useState<GameSnapshot>(() => createInitialGame())

  const handleMove = (direction: Direction) => {
    setGame((current) => {
      if (current.gameOver) {
        return current
      }

      const result = applyMove(current.board, direction)
      if (!result.moved) {
        return {
          ...current,
          gameOver: result.gameOver,
          won: current.won || result.won,
        }
      }

      return {
        board: result.board,
        score: current.score + result.scoreGained,
        won: current.won || result.won,
        gameOver: result.gameOver,
      }
    })
  }

  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent) => {
      const direction = KEY_TO_DIRECTION[event.key]
      if (!direction) {
        return
      }

      event.preventDefault()
      handleMove(direction)
    }

    window.addEventListener('keydown', onKeyDown)
    return () => window.removeEventListener('keydown', onKeyDown)
  }, [])

  const filledTiles = useMemo(
    () => game.board.flat().filter((value) => value !== null).length,
    [game.board],
  )

  return (
    <main className="app-shell">
      <header className="hero">
        <div>
          <p className="eyebrow">React + Vite + TypeScript</p>
          <h1>2048</h1>
          <p className="subtitle">Slide tiles with arrow keys or WASD, merge matches, and chase 2048.</p>
        </div>
        <button className="restart-button" onClick={() => setGame(createInitialGame())} type="button">
          Restart
        </button>
      </header>

      <ScorePanel score={game.score} won={game.won} gameOver={game.gameOver} />

      <section className="play-area">
        <GameBoard board={game.board} />
        <aside className="help-panel">
          <h2>How to play</h2>
          <ul>
            <li>Use arrow keys or WASD to move all tiles.</li>
            <li>Matching tiles merge once per move.</li>
            <li>Each valid move spawns one new tile.</li>
            <li>Reach 2048 to win. If no moves remain, the game ends.</li>
          </ul>
          <p className="meta">Filled tiles: {filledTiles} / 16</p>
        </aside>
      </section>
    </main>
  )
}

export default App

